"use client";

import { useState } from "react";
import { LiaClipboardListSolid } from "react-icons/lia";
import { MdPendingActions } from "react-icons/md";

export default function AdminDashboard() {
  const [selectedTab, setSelectedTab] = useState("blogs"); // default is blog lists

  return (
    <div className="flex h-screen font-sans">
      {/* Sidebar */}
      <div className="w-60 bg-sky-50 p-5 border-r-2 border-gray-300">
        <h2 className="text-2xl font-bold mb-10">Admin Panel</h2>

        <button
          className={`w-full py-3 px-4 mb-4 border-2 flex items-center gap-2 text-left font-semibold ${
            selectedTab === "pending"
              ? "bg-black text-white border-black"
              : "bg-white border-black hover:bg-gray-100"
          }`}
          onClick={() => setSelectedTab("pending")}
        >
          <MdPendingActions className="text-xl" /> Pending Blogs
        </button>

        <button
          className={`w-full py-3 px-4 mb-4 border-2 flex items-center gap-2 text-left font-semibold ${
            selectedTab === "blogs"
              ? "bg-black text-white border-black"
              : "bg-white border-black hover:bg-gray-100"
          }`}
          onClick={() => setSelectedTab("blogs")}
        >
          <LiaClipboardListSolid className="text-xl" /> Blog Lists
        </button>
      </div>

      {/* Content Area */}
      <div className="bg-[#fafafa] w-full p-10 overflow-y-auto">
        {selectedTab === "blogs" ? (
          <div>
            <h2 className="text-2xl font-bold mb-4">All Blogs</h2>
            {/* Put your blog list component here */}
            <p>This is where all blog entries would appear.</p>
          </div>
        ) : (
          <div>
            <h2 className="text-2xl font-bold mb-4">Pending Blogs</h2>
            {/* Put your pending blog review section here */}
            <p>This is where pending blogs for approval would appear.</p>
          </div>
        )}
      </div>
    </div>
  );
}
